// Stages 5-6 — Assemble & bundle. Stage III renders ONLY from argument-model.json (the II→III
// seam produced by serialize.mjs) — no source re-derivation. Emits the app's generated files
// (content.ts, evidence.ts) and vite-builds to one offline HTML.
// Usage: node build.mjs <argument-model.json> <app-dir> <out.html>
import { readFileSync, writeFileSync, copyFileSync } from 'node:fs';
import { execSync } from 'node:child_process';
import { join } from 'node:path';

const [modelPath, appDir, outHtml] = process.argv.slice(2);
const M = JSON.parse(readFileSync(modelPath, 'utf8'));

// evidence.ts: S-NNN -> {source, text}
const EVIDENCE = {};
for (const s of M.sources) EVIDENCE[s.id] = { source: s.claim, text: s.text };

// content.ts: the NodeContent tree App.tsx walks (developed_content -> body; component inline)
const nodes = {};
for (const n of Object.values(M.nodes)) {
  nodes[n.id] = {
    id: n.id, level: n.level, parent: n.parent, path: n.path, title: n.title,
    body: n.developed_content || '',
    finding: n.finding || undefined,
    finding_full: n.finding_full || undefined,
    component: n.component || undefined,
    children: n.children || [],
  };
}
const content = {
  meta: { source: M.meta.source, governing_thought: M.governing_thought, title: M.meta.title, kicker: M.meta.kicker },
  nodes, roots: M.roots,
};

writeFileSync(join(appDir, 'src/content.ts'),
  `// GENERATED by build.mjs from argument-model.json — do not edit.\nimport { Manifest } from './types';\nexport const manifest: Manifest = ${JSON.stringify(content)};\n`);
writeFileSync(join(appDir, 'src/evidence.ts'),
  `// GENERATED by build.mjs from argument-model.json — do not edit.\nexport const EVIDENCE: Record<string,{source:string;text:string}> = ${JSON.stringify(EVIDENCE)};\n`);

execSync('node_modules/.bin/vite build', { cwd: appDir, stdio: 'inherit' });
copyFileSync(join(appDir, 'dist/index.html'), outHtml);
const kb = (readFileSync(outHtml).length / 1024).toFixed(1);
console.log(`[build] rendered ${Object.keys(nodes).length} nodes, ${Object.values(nodes).filter((n) => n.component).length} components -> ${outHtml} (${kb} KB)`);
